var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"같은 시각. 챔버, <color=#ffd34c>구 콜롬비아 폐광</color> 인근 무인지대.","JPN":"同時刻、チェンバー。<color=#ffd34c>旧コロンビア廃鉱</color>付近の無人地帯。","ENG":"Meanwhile. Chamber, <color=#ffd34c>Abandoned Mine in Old Colombia</color> near No-man's land.","TWN":"同一時間，密室，<color=#ffd34c>舊哥倫比亞廢礦</color>附近無人地帶","DEU":"Meanwhile. Chamber, <color=#ffd34c>Abandoned Mine in Old Colombia</color> near No-man's land.","FRA":"Meanwhile. Chamber, <color=#ffd34c>Abandoned Mine in Old Colombia</color> near No-man's land."},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"대균열의 확장이 시작됐군요.","JPN":"大亀裂の拡張が始まりましたね。","ENG":"The expansion of the Grand Dimension Crevice has begun.","TWN":"大峽谷開始擴張了。"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"심층에 위치한 챔버 대균열의 영향력이 이정도라면, 다른 지부는 말할 것도 없을 겁니다.","JPN":"深層にあるチェンバー大亀裂の影響がこれほどなら、他の支部は言うまでもないでしょう。","ENG":"If the depths of Chamber's Grand Dimension Crevice already has this much influence, the other branches will be even worse.","TWN":"如果位於深層的密室大峽谷具有這樣的影響力，那其他分部就不用說了。"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그래. 마침 관리국 최고 등급 재난 경보도 발령된 참이네.","JPN":"そうね。ちょうど管理局の最高ランクの災難警報も発令されたわ。","ENG":"Yeah. The Administration just issued its highest-level disaster alert, too.","TWN":"沒錯，正好管理局也發布最高等級災難警報了。"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"타기리온이라는 녀석. 우리가 예상한 것보다 훨씬 본격적이야.","JPN":"タギリオンってやつ、アタシたちが予想してたよりずっと本格的ね。","ENG":"This Thagirion is a lot more serious than we expected.","TWN":"那個叫塔基里翁的傢伙，比我們想像中還要認真。"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"하하. 겁이라도 먹었어, 실비아?","JPN":"はは。怖気づいたのか、シルビア？","ENG":"Haha. Getting scared, Sylvia?","TWN":"哈哈，妳怕了嗎，希爾維亞？"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"뭐래. 이런 상황에서 태연하게 구는 건 너밖에 없거든?","JPN":"何よ、こんな状況で平然としていられる人ってあんたぐらいしかいないからね。","ENG":"Please. You're the only one who can act carefree right now.","TWN":"在說什麼？這種情況下只有我能表現出一副泰然自若的樣子。"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L17_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"좋은 게 좋은 거지. 어차피 맞닥트린 상황이라면 긍정적으로 생각하자고.","JPN":"まあまあ、立ち向かうしかないならポジティブに考えようじゃないか。","ENG":"Gotta keep it positive. If the situation's here, face it head on.","TWN":"不管怎樣都是好事，反正既然碰上了就要正向思考。"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"복잡해 보이지만, 정면승부를 거는 적에게 이쪽도 전력으로 부딪친다.","JPN":"複雑そうに見えるが、真正面からかかってくる敵にはこっちも全力で勝負する。","ENG":"It looks complicated, but if they come straight at us, we hit back with full force.","TWN":"雖然看起來很複雜，但面對正面交戰的敵人，我們也要全力以赴。"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"어때, 심플하지?","JPN":"どうだ、シンプルだろ？","ENG":"Simple, right?","TWN":"如何，很簡單吧？"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"근육 바보인 너야 그렇지. 우린 이것저것 하느라 바쁠 예정이라고.","JPN":"筋肉バカはそれでいいかもしれないけど、アタシたちは色々やるから忙しくなる予定なの。","ENG":"Says the musclehead. The rest of us will be busy juggling a thousand things.","TWN":"因為妳做事只憑一股熱血，我們會忙著做各種事情。"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"두 분. 거기까지 하시죠.","JPN":"2人とも、そこまでにしましょう。","ENG":"You two, that's enough.","TWN":"兩位，就到此為止吧。"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"작전에 앞서, 팀의 원활한 소통을 위한 통신 점검을 진행하겠습니다.","JPN":"作戦に先立ち、チームの円滑なコミュニケーションのために通信の点検を始めます。","ENG":"Before the operation, we'll run a comms check for any problems.","TWN":"在作戰之前，為了讓團隊溝通順暢，我要進行通訊檢查。"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"사전에 공유한대로 이번 작전의 지휘는 제가 맡게 되었으나.","JPN":"事前に共有したとおり、今回の作戦は僕が指揮を執ることになりましたが。","ENG":"As previously shared, I'll be commanding this operation.","TWN":"按照事前共享的內容，這次作戰由我負責指揮。"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"특정 상황에서의 변수 발생 시, 각 조에 소속된 명령권자의 지시를 우선적으로 따라주시길.","JPN":"特定の状況で予想外のことが発生した場合、各組に所属している命令権者の指示を優先してください。","ENG":"However, if variables arise, follow the order of the commander assigned to your unit.","TWN":"發生特定情況變數時，請優先遵照各組下達命令之人的指示。"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"subtitle","speaker":null,"text":{"KOREA":"챔버 대균열 작전팀, 알파\\n지휘관, 카일 웡 소령.","JPN":"チェンバー大亀裂作戦チーム、アルファ\\n指揮官、カイル・ウォン少佐","ENG":"[[","TWN":"密室大峽谷作戰組，阿爾法\\n指揮官，凱爾少校。","DEU":"[[","FRA":"[["},"stage":{"bg":"WAREHOUSE_01","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"각 팀. 응답 바랍니다.","JPN":"各チーム、応答願います。","ENG":"All teams, respond.","TWN":"各組請回答。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"여기는 HQ. 선로전환기 프로토타입의 제작은 끝마쳤다.","JPN":"こちらはHQ。線路転換器プロトタイプの製作は完了した。","ENG":"This is HQ. The prototype Track Switcher is complete.","TWN":"這裡是HQ，線路轉換器原型製作完成。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"북방합의체로부터 제공받은 이터니움 기술로 어떻게든 계면 붕괴는 막고 있지만…….","JPN":"北方合意体から提供してもらったエタニウム技術でなんとか界面崩壊は防いでいるが……","ENG":"Using Eternium tech supplied by the Northern Union, we're barely preventing the surface meltdown...","TWN":"雖然正在想盡辦法用北方和議會提供的永恆之金技術阻止介面塌陷……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"효율성이 최악인지라 이터니움 소모 속도가 상당해. 이건 임시방편에 불과할 거다.","JPN":"効率が最悪で、エタニウムの消耗がかなり速い。これじゃ一時凌ぎにしかならないと思うぞ。","ENG":"...But efficiency is awful, so Eternium consumption is huge. This should only be a stopgap.","TWN":"但可能是效率極差，永恆之金消耗速度非常快，這應該只是權宜之計。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"최적인 상태로 운용하려면, 역시 대균열 심부에 직접 설치해야겠지.","JPN":"最適の状態で運用するためには、やっぱり大亀裂深部に直接設置すべきだな。","ENG":"To run it optimally, we'll have to install it directly in the Grand Dimension Crevice's depths.","TWN":"如果想以最佳狀態運用，果然還是要直接設置在大峽谷深處。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"subtitle","speaker":null,"text":{"KOREA":"챔버 대균열 작전팀, HQ.\\n리더, 존 메이슨","JPN":"チェンバー大亀裂作戦チーム、HQ。\\nリーダー、ジョン・メイソン","ENG":"[[","TWN":"密室大峽谷作戰組，HQ。\\n隊長，約翰·梅森","DEU":"[[","FRA":"[["},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"당장은 시민들이 대피할 시간을 벌 수 있다면 충분합니다.","JPN":"今は市民が避難できる時間を稼ぐだけで十分です。","ENG":"For now, if we can buy civilians time to evacuate, that's enough.","TWN":"只要能暫時爭取居民撤離的時間就夠了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"대균열을 막아내는 건 부차적인 문제로 생각하시죠.","JPN":"大亀裂を止めるのはその次に考えましょう。","ENG":"Treat sealing the Grand Dimension Crevice as a secondary objective.","TWN":"就把阻擋大峽谷當成次要問題吧。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"마찬가지로, HQ. 대균열 내부에서의 통신망은 확보되었다.","JPN":"同じく、HQ。大亀裂内部の通信網は確保した。","ENG":"Likewise, HQ. Comms are secured within the Grand Dimension Crevice interior.","TWN":"這邊也一樣，HQ。已確保大峽谷內部的通訊網。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"시뮬레이션 결과. 대균열 심층으로 진입하더라도 양방향 소통은 원활할 예정이다.","JPN":"シミュレーション結果。大亀裂深部に進入しても両方向通信は円滑に行える。","ENG":"Simulations say two-way comms should remain stable even after we enter its depths.","TWN":"模擬結果，就算進入大峽谷深處，雙向溝通也會暢通無阻。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"앨버트… 우리… 아직 살아있냐……?","JPN":"アルバート……まだ、生きてるよな……？","ENG":"Albert... Are we... still alive...?","TWN":"亞伯特…我們…還活著嗎……？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"악마 같은 놈들… 하이테크 통신기를 가상좌표 기준으로 죄다 뜯어 고치라니…….","JPN":"悪魔みたいなやつらめ……ハイテク通信機を仮想座標基準に全部直せだなんて……","ENG":"Devilish bastards... Making us rebuild high-tech comms around virtual coordinates...","TWN":"這些惡魔般的傢伙…居然以虛擬座標為標準大改所有高科技通訊設備……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"심층 환경이라 어쩔 수 없다지만… 각 세션마다 유효한 문자열을 일일이 부여했다고…….","JPN":"深層環境だから仕方ないとはいえ……各セッションに有効な文字列をいちいち与えたのよ……","ENG":"I get that it's because of the Deep Floor conditions, but assigning valid strings to every single session...","TWN":"因為是深層環境也無可奈何…但每個區段都賦予了有效的字串……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"약간의 희생이 있었지만, 다-크 세븐의 힘으로 불가능을 가능으로 만들었지.","JPN":"少々の犠牲はあったが、ダーークセブンの力で不可能を可能にした。","ENG":"With some sacrifice, Daark Seven made the impossible possible.","TWN":"雖然做出一些犧牲，但憑藉Dark 7的力量，把不可能變成可能了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"여기는 브라보. 시민들의 대피도 차질 없이 진행되고 있네.","JPN":"こちらはブラボー。市民の避難も滞りなく進んでいる。","ENG":"This is Bravo. Civilian evacuations are proceeding smoothly.","TWN":"這裡是布拉伯，市民撤離也正在順利進行。"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"합중국 주요 인사들을 안전한 곳에 모시는 대로 나도 현장으로 합류하지.","JPN":"合衆国の要人たちを安全な場所へ送ってから、私も現場に合流する。","ENG":"Once key States personnel have evacuated to some place safe, I'll join you on site.","TWN":"把合眾國主要人士送到安全的地方後，我也會到現場會合。"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"subtitle","speaker":null,"text":{"KOREA":"챔버 대균열 작전팀, 브라보\\n리더, 마리아 안토노프 중장","JPN":"チェンバー大亀裂作戦チーム、ブラボー\\nリーダー、マリア・アントノフ中将","ENG":"[[","TWN":"密室大峽谷作戰組，布拉伯\\n隊長，瑪麗亞·安東諾夫中將","DEU":"[[","FRA":"[["},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"subtitle","speaker":null,"text":{"KOREA":"L31_1","JPN":"L31_1","ENG":"L31_1","TWN":"L31_1","DEU":"L31_1","FRA":"L31_1"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":null,"R":{"char_id":"L26_1","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"subtitle","speaker":null,"text":{"KOREA":"L40_1","JPN":"L40_1","ENG":"L40_1","TWN":"L40_1","DEU":"L40_1","FRA":"L40_1"},"stage":{"bg":"L38_1","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};